-- ================================================================
-- doddl Developmental Journey — Website Project Migration
-- ================================================================
-- Version:     1.0
-- Date:        April 2026
-- Source:      doddl-journey-project-plan.xlsx
-- ----------------------------------------------------------------
-- WHAT THIS DOES:
-- 1. Renames Website & Content project to Developmental Journey — Website
-- 2. Removes existing 5 tasks and 1 task group
-- 3. Inserts 12 task groups
-- 4. Inserts all 145 tasks with dates, owners, priorities, dependencies
-- ----------------------------------------------------------------
-- RUN IN: Supabase staging first, then production
-- VERIFY: SELECT COUNT(*) FROM tasks WHERE project_id = '10000000-0000-0000-0000-000000000009';
--         Expect 145
-- ================================================================

BEGIN;

-- 1. RENAME PROJECT
UPDATE projects SET
  name = 'Developmental Journey — Website',
  description = 'Full build of the doddl Developmental Journey on the website. 145 tasks across 12 workstreams: Strategy, UX, Visual Design, Copywriting, Photography, Shopify Build, Navigation, SEO, CRM, Analytics, Testing, and Launch. Kickoff: May 2026. Go-live target: July 2026.',
  start_date = '2026-05-21',
  due_date = '2026-07-23',
  priority = 'high'
WHERE id = '10000000-0000-0000-0000-000000000009';

-- 2. DELETE EXISTING TASKS FOR THIS PROJECT
DELETE FROM tasks WHERE project_id = '10000000-0000-0000-0000-000000000009';

-- 3. DELETE EXISTING TASK GROUPS FOR THIS PROJECT
DELETE FROM task_groups WHERE project_id = '10000000-0000-0000-0000-000000000009';

-- 4. INSERT 12 TASK GROUPS

-- 5. INSERT 145 TASKS

COMMIT;

-- ================================================================
-- VERIFICATION
-- ================================================================
